    const MOD: i64 = 1_000_000_007;
    let mut freq = HashMap::new();
    for p in points {
        let y = p[1];
        *freq.entry(y).or_insert(0) += 1;
    }
    let mut sum_c = 0;
    let mut sum_c_sq = 0;
    for (&y, &count) in &freq {
        let c = count * (count - 1) / 2;
        sum_c = (sum_c + c) % MOD;
        let c_sq = (c * c) % MOD;
        sum_c_sq = (sum_c_sq + c_sq) % MOD;
    }
    let total = (sum_c * sum_c - sum_c_sq) % MOD;
    let inv_2 = 500_000_004;
